use crossterm::{
    cursor::{Hide, MoveTo, Show},
    event::{self, Event, KeyCode, KeyEvent, KeyModifiers},
    execute,
    terminal::{self, Clear, ClearType, EnterAlternateScreen, LeaveAlternateScreen},
    QueueableCommand,
};
use std::collections::VecDeque;
use std::io::{self, Write};
use std::time::{Duration, Instant};

#[derive(Clone, Copy, PartialEq)]
enum Direction {
    Up,
    Down,
    Left,
    Right,
}

struct Snake {
    body: VecDeque<(u16, u16)>,
    direction: Direction,
}

struct Game {
    snake: Snake,
    food: (u16, u16),
    score: u32,
    width: u16,
    height: u16,
    game_over: bool,
}

impl Game {
    fn new(width: u16, height: u16) -> Self {
        let mut body = VecDeque::new();
        body.push_back((width / 2, height / 2));
        Game {
            snake: Snake {
                body,
                direction: Direction::Right,
            },
            food: (width / 4, height / 4),
            score: 0,
            width,
            height,
            game_over: false,
        }
    }

    fn spawn_food(&mut self) {
        use rand::Rng;
        let mut rng = rand::thread_rng();
        loop {
            let x = rng.gen_range(1..self.width - 1);
            let y = rng.gen_range(1..self.height - 1);
            if !self.snake.body.contains(&(x, y)) {
                self.food = (x, y);
                break;
            }
        }
    }

    fn step(&mut self) {
        if self.game_over {
            return;
        }

        let (head_x, head_y) = *self.snake.body.front().unwrap();
        let (mut next_x, mut next_y) = (head_x, head_y);

        match self.snake.direction {
            Direction::Up => next_y = next_y.saturating_sub(1),
            Direction::Down => next_y += 1,
            Direction::Left => next_x = next_x.saturating_sub(1),
            Direction::Right => next_x += 1,
        }

        if next_x == 0 || next_x >= self.width - 1 || next_y == 0 || next_y >= self.height - 1 {
            self.game_over = true;
            return;
        }

        if self.snake.body.contains(&(next_x, next_y)) {
            self.game_over = true;
            return;
        }

        self.snake.body.push_front((next_x, next_y));

        if (next_x, next_y) == self.food {
            self.score += 10;
            self.spawn_food();
        } else {
            self.snake.body.pop_back();
        }
    }
}

fn main() -> io::Result<()> {
    let mut stdout = io::stdout();
    terminal::enable_raw_mode()?;
    execute!(stdout, EnterAlternateScreen, Hide)?;

    let (width, height) = terminal::size()?;
    let mut game = Game::new(width, height);

    // Simple food spawning without rand for now to keep it minimal
    game.food = (width / 3, height / 3);

    let mut last_tick = Instant::now();
    let tick_rate = Duration::from_millis(100);

    loop {
        if event::poll(Duration::from_millis(10))? {
            if let Event::Key(KeyEvent {
                code,
                modifiers,
                ..
            }) = event::read()?
            {
                match code {
                    KeyCode::Char('c') if modifiers.contains(KeyModifiers::CONTROL) => break,
                    KeyCode::Esc | KeyCode::Char('q') => break,
                    KeyCode::Up if game.snake.direction != Direction::Down => {
                        game.snake.direction = Direction::Up
                    }
                    KeyCode::Down if game.snake.direction != Direction::Up => {
                        game.snake.direction = Direction::Down
                    }
                    KeyCode::Left if game.snake.direction != Direction::Right => {
                        game.snake.direction = Direction::Left
                    }
                    KeyCode::Right if game.snake.direction != Direction::Left => {
                        game.snake.direction = Direction::Right
                    }
                    _ => {}
                }
            }
        }

        if last_tick.elapsed() >= tick_rate {
            game.step();
            last_tick = Instant::now();

            if game.game_over {
                break;
            }

            stdout.queue(Clear(ClearType::All))?;

            // Draw border
            for x in 0..game.width {
                stdout.queue(MoveTo(x, 0))?.queue(crossterm::style::Print("#"))?;
                stdout
                    .queue(MoveTo(x, game.height - 1))?
                    .queue(crossterm::style::Print("#"))?;
            }
            for y in 0..game.height {
                stdout.queue(MoveTo(0, y))?.queue(crossterm::style::Print("#"))?;
                stdout
                    .queue(MoveTo(game.width - 1, y))?
                    .queue(crossterm::style::Print("#"))?;
            }

            // Draw food
            stdout
                .queue(MoveTo(game.food.0, game.food.1))?
                .queue(crossterm::style::Print("@"))?;

            // Draw snake
            for (i, &(x, y)) in game.snake.body.iter().enumerate() {
                stdout.queue(MoveTo(x, y))?.queue(crossterm::style::Print(
                    if i == 0 { "O" } else { "o" },
                ))?;
            }

            // Draw score
            stdout
                .queue(MoveTo(2, 0))?
                .queue(crossterm::style::Print(format!(" Score: {} ", game.score)))?;

            stdout.flush()?;
        }
    }

    execute!(stdout, Show, LeaveAlternateScreen)?;
    terminal::disable_raw_mode()?;

    println!("Game Over! Final Score: {}", game.score);

    Ok(())
}

