            self.snake.body.pop_back();
        }
    }
}

fn main() -> io::Result<()> {
    let mut stdout = io::stdout();
    terminal::enable_raw_mode()?;
    execute!(stdout, EnterAlternateScreen, Hide)?;

    let (width, height) = terminal::size()?;
    let mut game = Game::new(width, height);
    game.food = (width / 3, height / 3);

    let mut last_tick = Instant::now();
    let tick_rate = Duration::from_millis(100);

    loop {
        if event::poll(Duration::from_millis(10))? {
            if let Event::Key(KeyEvent {
                code,
                modifiers,
                ..
            }) = event::read()?
            {
                match code {
                    KeyCode::Char('c') if modifiers.contains(KeyModifiers::CONTROL) => break,
                    KeyCode::Esc | KeyCode::Char('q') => break,
                    KeyCode::Up if game.snake.direction != Direction::Down => {
                        game.snake.direction = Direction::Up
                    }
                    KeyCode::Down if game.snake.direction != Direction::Up => {
                        game.snake.direction = Direction::Down
                    }
                    KeyCode::Left if game.snake.direction != Direction::Right => {
                        game.snake.direction = Direction::Left
                    }
                    KeyCode::Right if game.snake.direction != Direction::Left => {
                        game.snake.direction = Direction::Right
                    }
                    _ => {}
                }
            }
        }

        if last_tick.elapsed() >= tick_rate {
            game.step();
            last_tick = Instant::now();

            if game.game_over {
                break;
            }

            stdout.queue(Clear(ClearType::All))?;

            // Draw border
            for x in 0..game.width {
                stdout.queue(MoveTo(x, 0))?.queue(crossterm::style::Print("#"))?;
                stdout
                    .queue(MoveTo(x, game.height - 1))?
                    .queue(crossterm::style::Print("#"))?;
            }
            for y in 0..game.height {
                stdout.queue(MoveTo(0, y))?.queue(crossterm::style::Print("#"))?;
                stdout
                    .queue(MoveTo(game.width - 1, y))?
                    .queue(crossterm::style::Print("#"))?;
            }

            // Draw food
            stdout
                .queue(MoveTo(game.food.0, game.food.1))?
                .queue(crossterm::style::Print("@"))?;

            // Draw snake
            for (i, &(x, y)) in game.snake.body.iter().enumerate() {
                stdout.queue(MoveTo(x, y))?.queue(crossterm::style::Print(
                    if i == 0 { "O" } else { "o" },
                ))?;
            }

            // Draw score
            stdout
                .queue(MoveTo(2, 0))?
                .queue(crossterm::style::Print(format!(" Score: {} ", game.score)))?;

            stdout.flush()?;
        }
    }

    execute!(stdout, Show, LeaveAlternateScreen)?;
    terminal::disable_raw_mode()?;

    println!("Game Over! Final Score: {}", game.score);

    Ok(())
}
